// ============================================
// BUILD APOLLO SEARCH CONFIG
// ============================================

const formData = $input.first().json;

// Parse job titles into array
const jobTitles = formData['Job Titles']
  .split(',')
  .map(t => t.trim())
  .filter(t => t.length > 0);

// Parse locations
const locations = formData['Locations']
  ? formData['Locations'].split(',').map(l => l.trim()).filter(l => l.length > 0)
  : [];

// Parse industries
const industries = formData['Industries']
  ? formData['Industries'].split(',').map(i => i.trim()).filter(i => i.length > 0)
  : [];

// Company size mapping
const sizeMap = {
  '1-10': '1,10',
  '11-50': '11,50',
  '51-200': '51,200',
  '201-500': '201,500',
  '501-1000': '501,1000',
  '1001-5000': '1001,5000',
  '5001+': '5001,10000',
  'Any': ''
};

const companySize = sizeMap[formData['Company Size']] || '';
const maxLeads = parseInt(formData['Number of Leads']) || 100;
const emailsOnly = formData['Include Emails Only'] === 'Yes - Only leads with emails';

// Build Apify actor input
const actorInput = {
  searchType: 'people',
  maxResults: maxLeads,
  includeEmails: true,
  titles: jobTitles,
  locations: locations.length > 0 ? locations : undefined,
  industries: industries.length > 0 ? industries : undefined,
  employeeRanges: companySize ? [companySize] : undefined
};

// Clean undefined values
Object.keys(actorInput).forEach(key => {
  if (actorInput[key] === undefined) {
    delete actorInput[key];
  }
});

return [{
  json: {
    actorInput,
    emailsOnly,
    maxLeads,
    searchCriteria: {
      jobTitles,
      locations,
      industries,
      companySize: formData['Company Size']
    },
    timestamp: new Date().toISOString()
  }
}];

// ============================================
// PROCESS AND FILTER LEADS
// ============================================

const items = $input.all();
const config = $('Build Search Config').first().json;
const emailsOnly = config.emailsOnly;

// Flatten and process leads
let leads = [];

for (const item of items) {
  const data = item.json;

  // Handle both array and object responses
  if (Array.isArray(data)) {
    leads = leads.concat(data);
  } else if (data.items && Array.isArray(data.items)) {
    leads = leads.concat(data.items);
  } else if (data.email || data.name || data.firstName) {
    leads.push(data);
  }
}

// Filter and clean leads
const processedLeads = leads
  .filter(lead => {
    // Filter out if emails only and no email
    if (emailsOnly && !lead.email && !lead.personalEmail && !lead.workEmail) {
      return false;
    }
    // Must have at least a name
    if (!lead.name && !lead.firstName && !lead.full_name) {
      return false;
    }
    return true;
  })
  .map((lead, index) => {
    // Normalize lead data structure
    return {
      id: index + 1,
      full_name: lead.name || lead.full_name || `${lead.firstName || ''} ${lead.lastName || ''}`.trim(),
      first_name: lead.firstName || lead.first_name || (lead.name ? lead.name.split(' ')[0] : ''),
      last_name: lead.lastName || lead.last_name || '',
      email: lead.email || lead.personalEmail || lead.workEmail || '',
      email_status: lead.emailStatus || lead.email_status || 'unknown',
      phone: lead.phone || lead.personalPhone || lead.workPhone || '',
      title: lead.title || lead.headline || lead.job_title || '',
      company: lead.company || lead.organizationName || lead.organization_name || '',
      company_website: lead.companyUrl || lead.company_website || lead.website || '',
      linkedin_url: lead.linkedinUrl || lead.linkedin_url || lead.profileUrl || '',
      location: lead.location || lead.city || '',
      industry: lead.industry || '',
      company_size: lead.employeeCount || lead.company_size || '',
      seniority: lead.seniority || '',
      scraped_at: config.timestamp
    };
  });

// Return stats and leads
const stats = {
  total_scraped: leads.length,
  after_filtering: processedLeads.length,
  with_email: processedLeads.filter(l => l.email).length,
  with_phone: processedLeads.filter(l => l.phone).length,
  with_linkedin: processedLeads.filter(l => l.linkedin_url).length
};

return [{
  json: {
    stats,
    leads: processedLeads,
    searchCriteria: config.searchCriteria
  }
}];

// Split leads into individual items for Google Sheets
const data = $input.first().json;
const leads = data.leads || [];

return leads.map(lead => ({ json: lead }));

// Generate summary report
const processData = $('Process Leads').first().json;
const stats = processData.stats;
const criteria = processData.searchCriteria;

const summary = `APOLLO LEAD SCRAPE COMPLETE

Search Criteria:
- Job Titles: ${criteria.jobTitles.join(', ')}
- Locations: ${criteria.locations.length > 0 ? criteria.locations.join(', ') : 'Any'}
- Industries: ${criteria.industries.length > 0 ? criteria.industries.join(', ') : 'Any'}
- Company Size: ${criteria.companySize || 'Any'}

Results:
- Total Scraped: ${stats.total_scraped}
- After Filtering: ${stats.after_filtering}
- With Email: ${stats.with_email}
- With Phone: ${stats.with_phone}
- With LinkedIn: ${stats.with_linkedin}

Leads saved to Google Sheets!`;

return [{ json: { summary, stats } }];
